import { motion, useReducedMotion } from 'framer-motion';
import { useEffect, useRef } from 'react';

export function MagneticButtonCursorPull({ active, children }: { active: boolean; children: React.ReactNode }) {
  const reduce = useReducedMotion();
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!active) return;
    const node = ref.current;
    node?.setAttribute('data-motion-state', 'entered');
    return () => node?.removeAttribute('data-motion-state');
  }, [active]);

  return (
    <motion.div
      ref={ref}
      initial={reduce ? { opacity: 0 } : { opacity: 0, y: 12 }}
      animate={active ? { opacity: 1, y: 0 } : { opacity: 0, y: reduce ? 0 : 12 }}
      transition={{ duration: reduce ? 0.01 : 0.18, ease: 'easeOut' }}
      aria-hidden={!active}
    >
      {children}
    </motion.div>
  );
}

